```cpp
// add+modify_eas_records.hpp
#pragma once

#include <filesystem>
#include <map>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

#include "eas_common.hpp"
using namespace sqlgen;
using namespace sqlgen::literals;

template<typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {

  if (records.empty()) return;

  sqlgen::sqlite::connect(db_path)
      .and_then([&records](auto&& conn) {
        return sqlgen::insert(conn, records);
      })
      .value();
}

void modify_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id,
                              const std::string& col_name,
                              const auto& new_value) {

  // Map table names to their corresponding update operations
  if (table_name == "Student") {
    sqlgen::sqlite::connect(db_path)
        .and_then([&record_id, &col_name, &new_value](auto&& conn) {
          return sqlgen::update(conn, 
                               sqlgen::set(col_name = new_value),
                               sqlgen::where("SNo"_c == record_id));
        })
        .value();
  }
  else if (table_name == "Course") {
    uint32_t id = std::stoul(record_id);
    sqlgen::sqlite::connect(db_path)
        .and_then([id, &col_name, &new_value](auto&& conn) {
          return sqlgen::update(conn, 
                               sqlgen::set(col_name = new_value),
                               sqlgen::where("CID"_c == id));
        })
        .value();
  }
  else if (table_name == "Score") {
    uint32_t id = std::stoul(record_id);
    sqlgen::sqlite::connect(db_path)
        .and_then([id, &col_name, &new_value](auto&& conn) {
          return sqlgen::update(conn, 
                               sqlgen::set(col_name = new_value),
                               sqlgen::where("ScID"_c == id));
        })
        .value();
  }
  else if (table_name == "Major") {
    uint32_t id = std::stoul(record_id);
    sqlgen::sqlite::connect(db_path)
        .and_then([id, &col_name, &new_value](auto&& conn) {
          return sqlgen::update(conn, 
                               sqlgen::set(col_name = new_value),
                               sqlgen::where("MID"_c == id));
        })
        .value();
  }
  else {
    throw std::runtime_error("Unknown table: " + table_name);
  }
}

void delete_eas_records_by_id(const std::string& table_name,
                              const std::string& record_id) {

