#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace batch_insert_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  float price;
  std::string category;
  int stock;
};

/**
 * Function: Perform efficient batch insertion of product data using a transaction.
 * 
 * @param products List of products to insert
 * @return true if all inserts succeed, false otherwise
 */
bool batch_insert_products(const std::vector<Product>& products) {
   using namespace sqlgen;
   using namespace sqlgen::literals;

   // Connect to database and perform operations
   auto result = sqlgen::sqlite::connect("test_db.sqlite")
                 .and_then(drop_table<Product> | if_exists)
                 .and_then(create_table<Product>)
                 .and_then([&products](auto conn) {
                     // Begin transaction
                     return begin_transaction(conn)
                         .and_then([&products](auto conn_with_transaction) {
                             // Insert all products
                             return write(conn_with_transaction, products);
                         })
                         .and_then(commit); // Commit if all inserts succeed
                 });

   // Return true if all operations succeeded, false otherwise
   return result.is_ok();
}

}  // namespace batch_insert_products
