#include <sstream>

namespace query_active_users_posts {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  sqlgen::DateTime created_at;
};

struct ActiveUser {
  static constexpr const char* tablename = "ActiveUserView";
  static constexpr bool is_view = true;
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

std::vector<ActiveUser> query_active_users_posts() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Connect to SQLite database
    auto db = sqlgen::sqlite::Database::connect("test_db.sqlite");

    // Create User table
    db.create_table<User>();

    // Create Post table
    db.create_table<Post>();

    // Define the date range
    auto start_date = "2025-12-01"_date;
    auto end_date = "2025-12-31"_date;

    // Execute the query to find active users
    auto active_users = db.select<ActiveUser>()
        .from<User>()
        .inner_join<Post>(on<User, Post>(&User::user_id, &Post::user_id))
        .where(ge(&Post::created_at, start_date) && le(&Post::created_at, end_date))
        .distinct()
        .exec();

    return active_users;
}

}  // namespace query_active_users_posts
```

