std::vector<OrderView> query_high_value_orders() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Create database connection
  sqlgen::sqlite::Connection conn("test_db.sqlite");

  // Build the query using sqlgen's type-safe query builder
  auto query = select(
      columns(&Order::order_id, &Customer::name, &Order::total_amount, &Order::order_date),
      from<Order>(),
      join<Customer>(on(&Order::customer_id, &Customer::customer_id)),
      where(gt(&Order::total_amount, 1000.0)),
