Looking at the code structure and the requirements, I need to implement the `query_product_sales_report` function using the `sqlgen` library. Based on the reference SQL and the code fragments, here's the complete implementation:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_product_sales_report {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string category;
};

struct Sale {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  double amount;
};

struct CategoryReport {
  std::string category;
  int total_qty;
  double total_amt;
};

struct ProductSalesReport {
  static constexpr const char* tablename = "ProductSalesReport";
  static constexpr bool is_view = true;
  std::string category;
  int total_qty;
  double total_amt;
};

std::vector<CategoryReport> query_product_sales_report() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Create database connection
    sqlgen::sqlite::Connection connection("test_db.sqlite");

    // Build the query using sqlgen DSL
    auto query = select(
        &Product::category,
        sqlgen::sum(&Sale::quantity).as("total_qty"),
        sqlgen::sum(&Sale::amount).as("total_amt")
    ) |
    from<Product>() |
    join<Sale>(&Product::product_id == &Sale::product_id) |
    group_by(&Product::category) |
    having(sqlgen::sum(&Sale::amount) > 5000.0);

    // Execute the query and return results
    return connection.read<std::vector<CategoryReport>>(query);
}

}  // namespace query_product_sales_report
