```cpp
#pragma once

#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace query_search_books_by_criteria {

struct Book {
  sqlgen::PrimaryKey<int> book_id;
  std::string title;
  std::string author;
  int year;
  std::string genre;
  double price;
};

struct BookFilters {
  std::optional<std::string> title_keyword;
  std::optional<int> min_year;
  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Start with base SELECT query
    auto query = select<Book>;

    // Build WHERE conditions dynamically based on provided filters
    std::optional<sqlgen::Condition> condition;

    if (filters.title_keyword) {
        auto title_condition = "title"_c.like("%" + *filters.title_keyword + "%");
        condition = condition ? *condition && title_condition : title_condition;
    }

    if (filters.min_year) {
        auto year_condition = "year"_c >= *filters.min_year;
        condition = condition ? *condition && year_condition : year_condition;
    }

    if (filters.genre) {
        auto genre_condition = "genre"_c == *filters.genre;
        condition = condition ? *condition && genre_condition : genre_condition;
    }

    if (filters.max_price) {
        auto price_condition = "price"_c <= *filters.max_price;
        condition = condition ? *condition && price_condition : price_condition;
    }

    // Apply WHERE clause if any conditions were added
    if (condition) {
        query = query.where(*condition);
    }

    // Execute the query and return results
    return sqlite::connect("test_db.sqlite")
           .and_then(query)
           .and_then(read<std::vector<Book>>)
           .value();
}

}  // namespace query_search_books_by_criteria
```

This implementation:

