Here's the complete implementation of the `manage_indexes` function using the `sqlgen` library:

```cpp
#pragma once

#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace schema_manage_indexes {

  struct Product {
    sqlgen::PrimaryKey<int> product_id;
    std::string sku;
    std::string name;
    std::string category;
    double price;
  };

  bool manage_indexes() {
    try {
      // Connect to the SQLite database
      sqlgen::SQLite db("test_db.sqlite");

      // Create the Product table
      db.create_table<Product>(sqlgen::if_not_exists);

      // Create indexes with IF NOT EXISTS logic
      // 1. Create standard index on category
      db.execute(R"(
        CREATE INDEX IF NOT EXISTS idx_product_category 
        ON Product(category)
      )");

      // 2. Create unique index on sku
      db.execute(R"(
        CREATE UNIQUE INDEX IF NOT EXISTS idx_product_sku 
        ON Product(sku)
      )");

      // 3. Create composite index on (name, price)
      db.execute(R"(
        CREATE INDEX IF NOT EXISTS idx_product_name_price 
        ON Product(name, price)
      )");

      return true;
    } catch (const std::exception& e) {
      // Log error (you might want to use a proper logging system)
      std::cerr << "Error managing indexes: " << e.what() << std::endl;
      return false;
    }
  }

}  // namespace schema_manage_indexes
