```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace schema_migration_add_column {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct UserAfter {
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> user_id;
  std::string username;
  std::string phone_number;
  bool is_active;
};

/**
 * Function: Perform schema migration to add new columns.
 * 
 * @return true if migration succeeds, false otherwise
 */
bool migration_add_column() {
  try {
    // Connect to the SQLite database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
      return false; // Connection failed
    }

    auto conn = *conn_result;

    // Attempt to add phone_number column
    auto phone_result = conn.execute(R"(
      ALTER TABLE User ADD COLUMN phone_number VARCHAR(20);
    )");

    if (!phone_result) {
      // Column might already exist, but we'll continue with the migration
      // In a real scenario, you might want to log this but not fail the entire migration
    }

    // Attempt to add is_active column
    auto active_result = conn.execute(R"(
      ALTER TABLE User ADD COLUMN is_active INTEGER DEFAULT 1;
    )");

    if (!active_result) {
      // Column might already exist, but we'll continue with the migration
      // In a real scenario, you might want to log this but not fail the entire migration
    }

    return true;

  } catch (const std::exception& e) {
    // Handle any unexpected exceptions
    return false;
  }
}

} // namespace schema_migration_add_column
