  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = std::move(*conn_result);

  try {
    // Start transaction
    auto transaction = conn.transaction();

    // Check if sender has sufficient funds
    auto sender_account = conn.read<Account>(where("account_id"_c == from_account_id));
    if (sender_account.empty() || sender_account[0].balance < amount) {
      transaction.rollback();
      return false;
    }

    // Update sender's balance (deduct amount)
    auto update_sender = conn.update<Account>(
      set("balance"_c = "balance"_c - amount),
      where("account_id"_c == from_account_id)
    );

    if (!update_sender) {
      transaction.rollback();
      return false;
    }

    // Update receiver's balance (add amount)
    auto update_receiver = conn.update<Account>(
      set("balance"_c = "balance"_c + amount),
      where("account_id"_c == to_account_id)
    );

    if (!update_receiver) {
      transaction.rollback();
      return false;
    }

    // Commit transaction
    transaction.commit();
    return true;

  } catch (const std::exception& e) {
    // Rollback on any exception
    return false;
  }
}

}  // namespace transaction_transfer_funds
