```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace update_order_status {

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  std::string status;
  sqlgen::DateTime order_date;
  double total_amount;
};

int update_order_status() {
   // Create database connection
   sqlgen::sqlite::Database db("test_db.sqlite");

   // Update pending orders older than 7 days to expired
   auto update1 = sqlgen::update<Order>(db)
      .set(&Order::status = "expired")
      .where(sqlgen::column(&Order::status) == "pending" 
             && sqlgen::column(&Order::order_date) < sqlgen::raw("DATE('now', '-7 days')"));

   // Update shipped orders to delivered (simulating delivery confirmation)
   auto update2 = sqlgen::update<Order>(db)
      .set(&Order::status = "delivered")
      .where(sqlgen::column(&Order::status) == "shipped");

   // Execute both updates and return total affected rows
   int affected_rows = update1.execute() + update2.execute();
   return affected_rows;
}

} // namespace update_order_status
```

