```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <string>
#include <iostream>

namespace analyze_social_network {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::string email;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> join_date;
  std::optional<std::string> city;
};

struct Friendship {
  int user1_id;
  int user2_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct FriendConnection {
  std::string user1_name;
  std::string user2_name;
};

struct MutualFriendResult {
  std::string username1;
  std::string username2;
  int mutual_friends_count;
};

struct FriendCountResult {
  std::string username;
  int friend_count;
};

/**
 * Analyze social network data by creating temporary SQL tables for User and Friendship.
 * Returns: std::vector<FriendConnection>.
 */
std::vector<FriendConnection> analyze_social_network_impl(const std::vector<User>& users, const std::vector<Friendship>& friendships) {
  using namespace sqlgen;

  // Create SQLite connection (in-memory database for this implementation)
  sqlite::Connection conn(":memory:");

  // Create tables
  conn.execute(CreateTable<User>{});
  conn.execute(CreateTable<Friendship>{});

  // Insert data
  conn.execute(Insert<User>{users});
  conn.execute(Insert<Friendship>{friendships});

  std::vector<FriendConnection> results;

  // 1. Find mutual friends using SELF-JOIN
  try {
    auto mutual_friends_query = R"(
      SELECT u1.username, u2.username, COUNT(f1.user2_id) as mutual_friends
      FROM User u1
      INNER JOIN Friendship f1 ON u1.user_id = f1.user1_id
      INNER JOIN Friendship f2 ON f1.user2_id = f2.user1_id
      INNER JOIN User u2 ON f2.user2_id = u2.user_id
      WHERE u1.user_id < u2.user_id
        AND EXISTS (
          SELECT 1 FROM Friendship f3 
          WHERE f3.user1_id = u1.user_id AND f3.user2_id = u2.user_id
        )
      GROUP BY u1.user_id, u2.user_id
      HAVING COUNT(f1.user2_id) > 0
    )";

    auto mutual_friends = conn.execute(mutual_friends_query);
    for (const auto& row : mutual_friends) {
      FriendConnection conn{
        .user1_name = row[0].as<std::string>(),
        .user2_name = row[1].as<std::string>()
      };
      results.push_back(conn);
    }
  } catch (const std::exception& e) {
    std::cerr << "Error in mutual friends query: " << e.what() << std::endl;
  }

  // 2. Find users with more than average friends using nested query
  try {
    auto popular_users_query = R"(
      SELECT u.username, COUNT(f.user2_id) as friend_count
      FROM User u
      LEFT JOIN Friendship f ON u.user_id = f.user1_id
      GROUP BY u.user_id, u.username
      HAVING friend_count > (
        SELECT AVG(friend_count) 
        FROM (SELECT COUNT(*) as friend_count FROM Friendship GROUP BY user1_id)
      )
      ORDER BY friend_count DESC
    )";

    auto popular_users = conn.execute(popular_users_query);
    for (const auto& row : popular_users) {
      // Add to results as connections (though this is individual users)
      FriendConnection conn{
        .user1_name = row[0].as<std::string>(),
        .user2_name = "has " + std::to_string(row[1].as<int>()) + " friends"
      };
      results.push_back(conn);
    }
  } catch (const std::exception& e) {
    std::cerr << "Error in popular users query: " << e.what() << std::endl;
  }

  // 3. Find friend-of-friend relationships
  try {
    auto friend_of_friend_query = R"(
      SELECT DISTINCT u1.username, u3.username
      FROM User u1
      JOIN Friendship f1 ON u1.user_id = f1.user1_id
      JOIN User u2 ON f1.user2_id = u2.user_id
      JOIN Friendship f2 ON u2.user_id = f2.user1_id
      JOIN User u3 ON f2.user2_id = u3.user_id
      WHERE u1.user_id != u3.user_id
        AND NOT EXISTS (
          SELECT 1 FROM Friendship f3 
          WHERE f3.user1_id = u1.user_id AND f3.user2_id = u3.user_id
        )
    )";

    auto fof_connections = conn.execute(friend_of_friend_query);
    for (const auto& row : fof_connections) {
      FriendConnection conn{
        .user1_name = row[0].as<std::string>(),
        .user2_name = row[1].as<std::string>()
      };
      results.push_back(conn);
    }
  } catch (const std::exception& e) {
    std::cerr << "Error in friend-of-friend query: " << e.what() << std::endl;
  }

  // 4. Count friends per user and identify most connected users
  try {
    auto friend_counts_query = R"(
      SELECT u.username, COUNT(f.user2_id) as friend_count
      FROM User u
      LEFT JOIN Friendship f ON u.user_id = f.user1_id
      GROUP BY u.user_id, u.username
      ORDER BY friend_count DESC
      LIMIT 5
    )";

    auto top_connected = conn.execute(friend_counts_query);
    for (const auto& row : top_connected) {
      FriendConnection conn{
        .user1_name = "Top: " + row[0].as<std::string>(),
        .user2_name = "Friends: " + std::to_string(row[1].as<int>())
      };
      results.push_back(conn);
    }
  } catch (const std::exception& e) {
    std::cerr << "Error in friend counts query: " << e.what() << std::endl;
  }

  // 5. Find users in the same city who are not yet friends (recommendation)
  try {
    auto same_city_recommendation_query = R"(
      SELECT u1.username, u2.username
      FROM User u1
      JOIN User u2 ON u1.city = u2.city AND u1.user_id < u2.user_id
      WHERE u1.city IS NOT NULL 
        AND u2.city IS NOT NULL
        AND NOT EXISTS (
          SELECT 1 FROM Friendship f 
          WHERE (f.user1_id = u1.user_id AND f.user2_id = u2.user_id)
             OR (f.user1_id = u2.user_id AND f.user2_id = u1.user_id)
        )
    )";

    auto recommendations = conn.execute(same_city_recommendation_query);
    for (const auto& row : recommendations) {
      FriendConnection conn{
        .user1_name = "Recommend: " + row[0].as<std::string>(),
        .user2_name = row[1].as<std::string>()
      };
      results.push_back(conn);
    }
  } catch (const std::exception& e) {
    std::cerr << "Error in same city recommendation query: " << e.what() << std::endl;
  }

  return results;
}

}  // namespace analyze_social_network
