```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace calculate_order_metrics {

struct OrderItem {
  sqlgen::PrimaryKey<int> item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  std::optional<double> discount_rate;
  std::optional<double> tax_rate;
};

struct OrderMetrics {
  int item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  double discount_rate;
  double tax_rate;
  double gross_total;
  double discounted_total;
  double final_total;
  double unit_cost;
  int quantity_group;
  double estimated_profit;
};

/**
 * Calculate per-item order metrics by loading the provided items into a temporary SQLite table
 * and evaluating SQL expressions for totals, discounts, taxes, cost, grouping, and estimated profit.
 * @param items Vector of OrderItem records to analyze.
 * @return std::vector<OrderMetrics> Analysis results for each order item.
 */
std::vector<OrderMetrics> calculate_order_metrics_impl(const std::vector<OrderItem>& items) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect(":memory:").value();

  // Create temporary table for OrderItem
  create_table<OrderItem>(conn) | if_not_exists;

  // Insert all order items into the table
  write(conn, items);

  // Build the SQL query with arithmetic operations
  auto query = select(
    "item_id"_c,
    "order_id"_c,
    "product_id"_c,
    "unit_price"_c,
    "quantity"_c,
    coalesce("discount_rate"_c, 0.0).as("discount_rate"),
    coalesce("tax_rate"_c, 0.0).as("tax_rate"),
    ("unit_price"_c * "quantity"_c).as("gross_total"),
    ("unit_price"_c * "quantity"_c * (1 - coalesce("discount_rate"_c, 0.0) / 100)).as("discounted_total"),
    ("unit_price"_c * "quantity"_c * (1 - coalesce("discount_rate"_c, 0.0) / 100) * 
     (1 + coalesce("tax_rate"_c, 0.0) / 100)).as("final_total"),
    ("unit_price"_c * "quantity"_c / "quantity"_c).as("unit_cost"),
    ("quantity"_c % 10).as("quantity_group"),
    ("unit_price"_c * 0.3).as("estimated_profit")
  ).from<OrderItem>();

  // Execute the query and return results
  auto results = read<std::vector<OrderMetrics>>(conn, query).value();
  return results;
}

}  // namespace calculate_order_metrics
```

This implementation:

1. **Connects to an in-memory SQLite database** using `sqlgen::sqlite::connect(":memory:")`
2. **Creates the OrderItem table** using `create_table<OrderItem>` with `if_not_exists` modifier
3. **Inserts all provided items** using `sqlgen::write(conn, items)`
4. **Builds the complex SQL query** using `sqlgen::select()` with:
   - **COALESCE** to handle optional discount_rate and tax_rate fields
   - **Arithmetic operations**: multiplication (`*`), division (`/`), modulo (`%`), addition and subtraction
   - **Column aliases** (`.as()`) to match the OrderMetrics struct fields
5. **Executes the query** using `sqlgen::read<std::vector<OrderMetrics>>()`
6. **Returns the comprehensive order metrics** including all calculated business metrics

The query performs all the required calculations:
- **Gross total**: unit_price × quantity
- **Discounted total**: applies discount percentage
- **Final total**: adds tax to discounted amount  
- **Unit cost**: gross total ÷ quantity
- **Quantity groups**: using modulo 10 operation
- **Estimated profit**: 30% of unit price

The implementation handles nullable fields properly using `COALESCE` and follows the sqlgen library patterns shown in the test examples.

