  using namespace sqlgen;
  auto conn = sqlite::connect("test_db.sqlite").value();
  drop<Customer>(conn);
  drop<Order>(conn);
  drop<Payment>(conn);
  create_table<Customer>(conn);
  create_table<Order>(conn);
  create_table<Payment>(conn);

  insert(conn, std::vector<Customer>{{1, "Alice"}, {2, "Bob"}});
  insert(conn, std::vector<Order>{{1, 1, sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">{"2024-01-01 10:00:00"}},
                                  {2, 2, sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">{"2024-01-02 10:00:00"}}});
  insert(conn, std::vector<Payment>{{1, 1, 100.0}, {2, 2, 150.0}});

  auto rows = join_orders_customers_payments();
  ASSERT_EQ(rows.size(), 2);
  EXPECT_GE(rows[0].amount, rows[1].amount);
