Here's the complete implementation of the `replace_text_in_notes` function:

```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace replace_text_in_notes {

struct Note {
  sqlgen::PrimaryKey<int> note_id;
  std::string content;
};

struct UpdatedNote {
  sqlgen::PrimaryKey<int> note_id;
  std::string updated_content;
};

/**
 * description: replace_text_in_notes.
 * This function demonstrates how to replace text in notes using sqlgen update API.
 * It replaces all occurrences of "foo" with "bar" in the content column of the Note table.
 * Returns: std::vector<UpdatedNote>.
 */
std::vector<UpdatedNote> replace_text_in_notes() {
  // Connect to SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn) {
    // Return empty vector if connection fails
    return {};
  }

  // Read all existing notes
  auto notes_result = conn.and_then(sqlgen::read<std::vector<Note>>);
  if (!notes_result) {
    return {};
  }

  std::vector<UpdatedNote> updated_notes;
  auto& notes = *notes_result;

  // Process each note: replace "foo" with "bar"
  for (const auto& note : notes) {
    std::string updated_content = note.content;

    // Replace all occurrences of "foo" with "bar"
    size_t pos = 0;
    while ((pos = updated_content.find("foo", pos)) != std::string::npos) {
      updated_content.replace(pos, 3, "bar");
      pos += 3; // Move past the replacement
    }

    // Only update if content actually changed
    if (updated_content != note.content) {
      // Create updated note object
      Note updated_note{note.note_id, updated_content};

      // Update the database
      conn.and_then(sqlgen::update(updated_note));
    }

    // Add to result vector for verification
    updated_notes.push_back(UpdatedNote{note.note_id, updated_content});
  }

  return updated_notes;
}

}  // namespace replace_text_in_notes
```

