  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Query 1: Filter rows where bio IS NULL
  auto null_bio_results = conn | read<std::vector<Profile>> 
                         | where("bio"_c.is_null())
                         | select("profile_id"_c, "display_name"_c);

  // Query 2: Filter rows where avatar_url IS NOT NULL  
  auto not_null_avatar_results = conn | read<std::vector<Profile>> 
                                | where("avatar_url"_c.is_not_null())
                                | select("profile_id"_c, "display_name"_c);

  // Combine both results
  std::vector<Result> combined_results;

  // Add results from first query (bio IS NULL)
  for (const auto& row : null_bio_results) {
    combined_results.push_back(Result{
      std::get<0>(row),  // profile_id
      std::get<1>(row)   // display_name
    });
  }

  // Add results from second query (avatar_url IS NOT NULL)
  for (const auto& row : not_null_avatar_results) {
    combined_results.push_back(Result{
      std::get<0>(row),  // profile_id
      std::get<1>(row)   // display_name
    });
  }

  return combined_results;
}

}  // namespace column_is_null_checks

