namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the database
  auto result = sqlgen::sqlite::connect("test_db.sqlite")
    .and_then([](auto conn) {
      // Use a custom SQL query to perform the FULL JOIN simulation
      // SQLite doesn't support FULL JOIN directly, so we use UNION of LEFT JOINs
      const char* full_join_sql = R"(
        SELECT s.name as supplier_name, p.name as product_name
        FROM Supplier s
        LEFT JOIN Product p ON s.supplier_id = p.supplier_id
        UNION ALL
        SELECT NULL as supplier_name, p.name as product_name
        FROM Product p
        WHERE NOT EXISTS (SELECT 1 FROM Supplier s WHERE s.supplier_id = p.supplier_id)
      )";

      // Execute the custom SQL query
      return conn.execute(full_join_sql).and_then([conn]() {
        // Read the results into our SupProd structure
        // The library should automatically map column names to struct field names
        return sqlgen::read<std::vector<SupProd>>(conn);
      });
    });

  if (result) {
    return result.value();
  }

  // Return empty vector if there was an error
  return {};
}

}  // namespace full_join_suppliers_products
