 * Returns: std::vector<Book>, ordered by pages in descending order.
 */
std::vector<Book> select_from_read_to_vector() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database and execute the query
  auto result = sqlgen::sqlite::connect()
                .and_then(select_from<Book> | order_by("pages"_c.desc()) | to<std::vector<Book>>);

  // Return the result or empty vector if there's an error
