inline auto concat_function() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Construct a query to select CONCAT(first_name, ' ', last_name) as full_name
    return select(function<"CONCAT">("first_name"_c, " "_s, "last_name"_c).as("full_name"))
           .from<Person>();
