inline std::string in_operator_usage() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Construct a query to select items where code IN (1, 2, 3)
  auto query = select<Status>().where(in_("code"_c, {1, 2, 3}));

  // Return the generated SQL string
  return query.to_sql();
