namespace order_by_descending {

struct Score {
  sqlgen::PrimaryKey<int> id;
  int points;
};

/**
 * This function demonstrates ORDER BY DESC.
 * Returns: std::string.
 */
inline std::string order_by_descending() {
    using namespace sqlgen;
    using namespace sqlgen::literals;

    // Create a query that selects from Score table and orders by points in descending order
    auto query = select<Score>().order_by("points"_c.desc());

    // Convert the query to SQL string
    return to_sql(query);
}

}  // namespace order_by_descending
```

