#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace like_pattern_matching {

struct Product {
  sqlgen::PrimaryKey<int> id;
  std::string name;
};

/**
 * This function demonstrates LIKE pattern matching.
 * Returns: std::string containing the generated SQL.
 */
inline std::string like_pattern_matching() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Construct a query to select products where name LIKE 'A%'
  auto query = select<Product>.where(like("name"_c, "A%"));

  return to_sql(query);
}

}  // namespace like_pattern_matching
```

