```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace group_by_with_aggregations {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  std::string content;
};

struct Stats {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  int post_count;
  std::optional<double> avg_length;
};

/**
 * Description: This function retrieves user statistics including post count and average post length.
 * Returns: std::vector<Stats>.
 */
std::vector<Stats> group_by_with_aggregations() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  sqlgen::sqlite::Database db("test_db.sqlite");

  // Build the query with GROUP BY and aggregations
  auto query = db.select(&User::user_id, &User::name, 
                        count(&Post::post_id).as("post_count"),
                        avg("length(content)").as("avg_length"))
                .from<User>()
                .join<Post>(on_(&User::user_id == &Post::user_id))
                .group_by(&User::user_id, &User::name);

  // Execute the query and get results
  auto results = query.template get<int, std::string, int, std::optional<double>>();

  // Convert results to Stats objects
  std::vector<Stats> stats;
  for (auto [user_id, name, post_count, avg_length] : results) {
    stats.push_back(Stats{
      .user_id = user_id,
      .name = name,
      .post_count = post_count,
      .avg_length = avg_length
    });
  }

  return stats;
}

}  // namespace group_by_with_aggregations
```

